export const processAIQuery = async (query: string): Promise<AIResponse> => {
  await new Promise(resolve => setTimeout(resolve, 600));
  const lowerQuery = query.toLowerCase();

  for (const entry of KNOWLEDGE_BASE) {
    if (entry.keywords.some(kw => lowerQuery.includes(kw))) {
      const response: AIResponse = {
        text: entry.response,
        action: entry.action,
        suggestions: [{ label: 'Узнать больше', description: 'Задай еще вопрос', action: { type: 'OPEN_ENGINE' } }]
      };
      if (entry.tips) response.tips = entry.tips;
      if (entry.examples) response.examples = entry.examples;
      if (entry.links) response.links = entry.links;
      return response;
    }
  }

  const simpleChordMatch = query.match(/^[A-G][b#]?(?:m|maj|dim|aug|sus|7|9|11|13|maj7|m7|m9|m11|maj9|add9|add11|alt)?\d*$/i);
  if (simpleChordMatch && !lowerQuery.includes('chord') && !lowerQuery.includes('покажи')) {
    const chord = simpleChordMatch[0];
    const cleanKey = chord.replace(/[^A-G#b]/g, '');
    const isMinor = chord.includes('m');
    return {
      text: `🎸 Я нашёл аккорд **${chord}**. Что ты хочешь сделать?`,
      options: [
        { id: 'show', title: `📖 Показать аппликатуру ${chord}`, action: { type: 'OPEN_CHORD', payload: { chord } } },
        { id: 'backing', title: `🎧 Найти минусовку ${chord}`, action: { type: 'SEARCH_BACKING', payload: { query: `${chord} guitar backing track` } } },
        { id: 'playover', title: `🎯 Обыграть ${chord} (арпеджио)`, action: { type: 'OPEN_AUTOTAB', payload: { key: cleanKey, mode: isMinor ? 'minor' : 'major' } } }
      ],
      links: buildTrackSearchLinks(`${chord} guitar backing track`),
    };
  }

  for (const queryPattern of commonQueries) {
    const match = query.match(queryPattern.pattern);
    if (match) {
      const response = guitarResponses[queryPattern.action]?.(match);
      if (response) return response;
    }
  }

  const isLookingForTrack = lowerQuery.includes('track') || lowerQuery.includes('минус') || lowerQuery.includes('джем');
  if (isLookingForTrack) {
    return {
      text: `🎵 Подбираю идеи минусовок. Вот где можно искать:`,
      platformOptions: [
        { platform: 'youtube', label: 'YouTube', icon: '▶️' },
        { platform: 'rutube', label: 'RUTUBE', icon: '📺' },
        { platform: 'vk', label: 'VK Видео', icon: '📱' }
      ],
      searchQuery: `${query.replace(/минус|track/gi, '').trim()} guitar backing track`
    };
  }

  return {
    text: '🤖 Привет! Я TouchGrass AI — ваш музыкальный ассистент.\n\n🎸 Что я умею:\n• Находить минусовки: *«Найди блюз минус в Am»*\n• Показывать аккорды: *«Покажи Cmaj7»*\n• Подсвечивать лады: *«Как обыграть E7?»*\n• Генерировать табы: *«Придумай фразу в Dorian»*\n• Настроить метроном: *«120 bpm»*',
    examples: ['Set tempo to 96 BPM', 'Show Cmaj7', 'Build a blues solo in E'],
    suggestions: [
      { label: '🎸 Показать аккорд C', action: { type: 'OPEN_CHORD', payload: { chord: 'C' } } },
      { label: '🎧 Найти минусовку в Am', action: { type: 'SEARCH_BACKING', payload: { query: 'Am guitar backing track' } } },
      { label: '🎵 Установить BPM 120', action: { type: 'SET_BPM', payload: { bpm: 120 } } },
      { label: '🎼 Сгенерировать соло в E', action: { type: 'OPEN_AUTOTAB', payload: { key: 'E', mode: 'major' } } }
    ]
  };
};

