export type Technique = 
  | 'none' | 'hammer' | 'pull' | 'slide' | 'vibrato' | 'bend' | 'prebend'
  | 'unison_bend' | 'grace' | 'fall' | 'ghost' | 'choke' | 'mute'
  | 'harmonic' | 'artificial_harmonic' | 'open' | 'pick_squeal';

export interface LickNote {
  string: number;
  fret: number | null;
  duration: 'quarter' | 'eighth' | 'sixteenth' | 'dotted_eighth' | 'half' | 'whole';
  isRest?: boolean;
  technique?: Technique;
  tiedToNext?: boolean;
  velocity?: number;
  accent?: boolean;
  durationFactor?: number;
  legatoGroup?: number;
  isLegatoEnd?: boolean;
  isPalmMuted?: boolean;
  isOpenString?: boolean;
  pickDirection?: 'down' | 'up';
}

export interface Lick {
  id: string;
  name: string;
  notes: LickNote[];
  tempo?: number;
  swing?: number;
  feel?: 'straight' | 'shuffle' | 'half_time';
}

const ALL_NOTES = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
const STANDARD_TUNING = ['E', 'B', 'G', 'D', 'A', 'E'];

// ---- ВСПОМОГАТЕЛЬНЫЕ ИНТЕРФЕЙСЫ И СТРУКТУРЫ ДЛЯ МОТИВНОГО РАЗВИТИЯ ----

interface Motif {
  notes: LickNote[];
  duration: number;
}

interface SoloStructure {
  intro: number;
  development: number;
  climax: number;
  outro: number;
}

// ---- НОВЫЙ ГЕНЕРАТОР С МОТИВНЫМ РАЗВИТИЕМ ----

function generateMotif(scaleNotes: string[], chordNotes: string[]): Motif | null {
  if (scaleNotes.length < 3) return null;

  const motifLength = Math.floor(Math.random() * 3) + 2; // 2-4 ноты
  const motifNotes: LickNote[] = [];
  let currentString = Math.floor(Math.random() * 3) + 2; // 2-4 струны

  for (let i = 0; i < motifLength; i++) {
    const useChordNote = Math.random() < 0.7;
    const sourceNotes = useChordNote && chordNotes.length > 0 ? chordNotes : scaleNotes;
    const selectedNote = sourceNotes[Math.floor(Math.random() * sourceNotes.length)];

    let fret = findFretForNote(selectedNote, currentString, 4, 12, false);
    if (fret === -1 || fret > 12) {
      for (let attempt = 0; attempt < 3; attempt++) {
        const altString = Math.floor(Math.random() * 4) + 1;
        const altFret = findFretForNote(selectedNote, altString, 4, 12, false);
        if (altFret !== -1 && altFret <= 12) {
          currentString = altString;
          fret = altFret;
          break;
        }
      }
    }
    if (fret === -1 || fret > 12) {
      fret = Math.floor(Math.random() * 7) + 5;
    }

    const duration: LickNote['duration'] = i === motifLength - 1 ? 'quarter' : 'eighth';
    motifNotes.push({
      string: currentString,
      fret: Math.max(0, Math.min(24, fret)),
      duration: duration,
      technique: 'none',
      velocity: 0.7 + Math.random() * 0.2,
      accent: i === 0,
      durationFactor: 0.9 + Math.random() * 0.2,
      pickDirection: Math.random() > 0.5 ? 'down' : 'up',
    });

    if (i < motifLength - 1) {
      const newString = Math.max(0, Math.min(5, currentString + (Math.random() > 0.5 ? 1 : -1)));
      if (newString >= 1 && newString <= 4) {
        currentString = newString;
      }
    }
  }

  const duration = motifNotes.reduce((acc, n) => acc + (n.duration === 'quarter' ? 1 : 0.5), 0);
  return { notes: motifNotes, duration };
}

function developMotif(
  motif: Motif,
  _scaleNotes: string[], // не используется, но оставлено для совместимости
  _chordNotes: string[], // не используется
  targetBeats: number,
  _intensity: number = 1.0,
  section: 'intro' | 'development' | 'climax' = 'development'
): LickNote[] {
  const result: LickNote[] = [];
  let currentBeat = 0;
  const motifDuration = motif.duration || 1;

  while (currentBeat < targetBeats) {
    const variation = motif.notes.map((note, index) => {
      const newNote = { ...note };

      if (section === 'climax') {
        if (index === 0 && Math.random() < 0.4) newNote.technique = 'bend';
        if (index === motif.notes.length - 1 && Math.random() < 0.5) newNote.technique = 'vibrato';
      } else if (section === 'development') {
        if (index === 0 && Math.random() < 0.3) newNote.technique = 'slide';
        if (index > 0 && Math.random() < 0.3) newNote.technique = Math.random() > 0.5 ? 'hammer' : 'pull';
      }

      if (section === 'climax' && Math.random() < 0.3) {
        newNote.accent = true;
        newNote.velocity = Math.min(1, (newNote.velocity || 0.7) * 1.3);
      }

      if (Math.random() < 0.2) {
        const durations: LickNote['duration'][] = ['eighth', 'quarter', 'sixteenth'];
        newNote.duration = durations[Math.floor(Math.random() * durations.length)];
      }

      return newNote;
    });

    if (section === 'intro' && result.length > 0 && Math.random() < 0.3) {
      result.push({
        string: 0,
        fret: null,
        duration: 'eighth',
        isRest: true
      });
      currentBeat += 0.5;
    }

    result.push(...variation);
    currentBeat += motifDuration;

    if (currentBeat < targetBeats && Math.random() < 0.2) {
      result.push({
        string: 0,
        fret: null,
        duration: 'eighth',
        isRest: true
      });
      currentBeat += 0.5;
    }
  }

  while (currentBeat > targetBeats) {
    const removed = result.pop();
    if (removed) {
      currentBeat -= (removed.duration === 'quarter' ? 1 : 0.5);
    }
  }

  return result;
}

function generateFallbackLick(
  _scaleNotes: string[], // не используется
  bpm: number,
  _timeSignature: { beats: number; noteValue: number }
): Lick {
  const notes: LickNote[] = [];
  const strings = [3, 2, 2, 3, 4, 3];
  const frets = [5, 7, 9, 7, 5, 7];

  for (let i = 0; i < strings.length; i++) {
    notes.push({
      string: strings[i],
      fret: frets[i],
      duration: i === strings.length - 1 ? 'quarter' : 'eighth',
      technique: i === strings.length - 1 ? 'vibrato' : 'none',
      velocity: 0.7,
      accent: i === 0,
      durationFactor: 1,
      pickDirection: 'down',
    });
  }

  return {
    id: `fallback-${Date.now()}`,
    name: 'Fallback Lick',
    notes: notes,
    tempo: bpm
  };
}

// ---- ОСНОВНАЯ ФУНКЦИЯ ГЕНЕРАЦИИ ЛИКА ----

export const generateSmartLick = (
  scaleNotes: string[],
  _keyNote: string,
  _mode: string,
  bpm: number = 120,
  _timeSignature: { beats: number; noteValue: number } = { beats: 4, noteValue: 4 },
  _bar: number = 0,
  chordNotes: string[] = []
): Lick => {
  const safeScaleNotes = (scaleNotes && scaleNotes.length > 0) ? scaleNotes : ['C', 'D', 'E', 'G', 'A'];
  const safeChordNotes = (chordNotes && chordNotes.length > 0) ? chordNotes : [safeScaleNotes[0], safeScaleNotes[2], safeScaleNotes[4]];

  const motif = generateMotif(safeScaleNotes, safeChordNotes);
  if (!motif) {
    return generateFallbackLick(safeScaleNotes, bpm, _timeSignature);
  }

  const structure: SoloStructure = { intro: 0.25, development: 0.5, climax: 0.25, outro: 0 };
  const totalBeats = 4 * _timeSignature.beats;
  const introBeats = totalBeats * structure.intro;
  const developmentBeats = totalBeats * structure.development;
  const climaxBeats = totalBeats * structure.climax;

  let allNotes: LickNote[] = [];

  const introNotes = developMotif(motif, safeScaleNotes, safeChordNotes, introBeats, 0.8, 'intro');
  allNotes = allNotes.concat(introNotes);

  const developmentNotes = developMotif(motif, safeScaleNotes, safeChordNotes, developmentBeats, 1.0, 'development');
  allNotes = allNotes.concat(developmentNotes);

  const climaxNotes = developMotif(motif, safeScaleNotes, safeChordNotes, climaxBeats, 1.2, 'climax');
  allNotes = allNotes.concat(climaxNotes);

  if (allNotes.length > 0) {
    const lastNote = allNotes[allNotes.length - 1];
    if (lastNote && lastNote.fret !== null) {
      const tonicFret = findFretForNote(safeScaleNotes[0], lastNote.string, 0, 24, false);
      if (tonicFret !== -1) {
        allNotes.push({
          ...lastNote,
          fret: tonicFret,
          duration: 'half',
          technique: 'vibrato',
          accent: true,
          durationFactor: 1.5,
        });
      }
    }
  }

  return {
    id: `lick-${Date.now()}`,
    name: `Melodic Solo in ${_keyNote} ${_mode}`,
    notes: allNotes,
    tempo: bpm
  };
};

// ---- ВСПОМОГАТЕЛЬНАЯ ФУНКЦИЯ ПОИСКА ЛАДА ----

const findFretForNote = (
  targetNote: string,
  targetStringIdx: number,
  minFret: number = 0,
  maxFret: number = 21,
  preferOpen: boolean = true
): number => {
  const normalizedTarget = normalizeRoot(targetNote.replace(/[0-9]/g, ''));
  const openNote = STANDARD_TUNING[targetStringIdx];
  let baseDistance = (ALL_NOTES.indexOf(normalizedTarget) - ALL_NOTES.indexOf(openNote) + 12) % 12;
  
  if (preferOpen && baseDistance === 0) return 0;
  
  let bestFret = baseDistance;
  let bestDistance = Math.abs(baseDistance - 5);
  for (let octave = -1; octave <= 1; octave++) {
    const candidate = baseDistance + octave * 12;
    if (candidate >= minFret && candidate <= maxFret) {
      const dist = Math.abs(candidate - 5);
      if (dist < bestDistance) {
        bestDistance = dist;
        bestFret = candidate;
      }
    }
  }
  return bestFret;
};

// ===========================================================
// 🔥 СИНХРОНИЗИРОВАННЫЙ ГЕНЕРАТОР СОЛО (4 ТАКТА) - С ПОДДЕРЖКОЙ ВСЕХ АККОРДОВ
// ===========================================================

export interface SyncChord {
  name: string;
  beatStart: number;
  durationBeats: number;
  notes: string[]; 
}

export interface SyncSoloData {
  bars: number;
  totalBeats: number;
  chords: SyncChord[];
  notes: any[]; 
  tips: string[];
}

const DURATION_TO_BEATS: Record<string, number> = {
  'whole': 4, 'dotted_half': 3, 'half': 2, 'dotted_quarter': 1.5, 'quarter': 1, 'dotted_eighth': 0.75, 'eighth': 0.5, 'sixteenth': 0.25
};

// ---- ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ДЛЯ АККОРДОВ ----

const parseChord = (chordName: string): { root: string; quality: string } => {
  const match = chordName.match(/^([A-G][b#]?)(.*)$/);
  if (!match) return { root: 'C', quality: 'maj' };
  return { root: match[1], quality: match[2] || 'maj' };
};

const getChordQuality = (mode: string, degree: number): string => {
  const isMajor = mode === 'major' || mode === 'ionian' || mode === 'lydian' || mode === 'mixolydian';
  const isMinor = mode === 'minor' || mode === 'aeolian' || mode === 'dorian' || 
                  mode === 'phrygian' || mode === 'harmonic_minor' || mode === 'melodic_minor';
  const isBlues = mode === 'blues' || mode === 'pentatonic';

  if (isMajor) {
    if (degree === 0) return 'maj';
    if (degree === 1) return 'm';
    if (degree === 2) return 'm';
    if (degree === 3) return 'maj';
    if (degree === 4) return 'maj';
    if (degree === 5) return 'm';
    if (degree === 6) return 'dim';
    return 'maj';
  }
  
  if (isMinor || isBlues) {
    if (degree === 0) return 'm';
    if (degree === 1) return 'dim';
    if (degree === 2) return 'maj';
    if (degree === 3) return 'm';
    if (degree === 4) return 'm';
    if (degree === 5) return 'maj';
    if (degree === 6) return 'maj';
    return 'm';
  }

  return 'maj';
};

const getChordIntervals = (quality: string): { third: number; fifth: number } => {
  switch (quality) {
    case 'maj': return { third: 4, fifth: 7 };
    case 'm': return { third: 3, fifth: 7 };
    case 'dim': return { third: 3, fifth: 6 };
    case 'aug': return { third: 4, fifth: 8 };
    default: return { third: 4, fifth: 7 };
  }
};

// ---- ОСНОВНАЯ ФУНКЦИЯ ГЕНЕРАЦИИ 4-ТАКТОВОГО СОЛО ----

export const generateSynchronizedSolo = (
  scaleNotes: string[], 
  keyNote: string,
  mode: string,
  timeSignature: TimeSignature,
  targetChord: string = '',
  chordNotes: string[] = [],
  forceAllChords: boolean = false
): SyncSoloData => {
  const bars = 4;
  const beatsPerBar = timeSignature.beats;
  const totalBeats = bars * beatsPerBar;
  
  const chords: SyncChord[] = [];
  
  const keyIdx = ALL_NOTES.indexOf(normalizeRoot(keyNote || scaleNotes[0] || 'C'));
  
  const isMinor = mode.includes('minor') || mode.includes('aeolian') || 
                  mode.includes('dorian') || mode.includes('phrygian') || 
                  mode === 'blues' || mode === 'pentatonic';

  // Прогрессия аккордов
  let progression: number[];
  const modeLower = mode.toLowerCase();
  
  if (modeLower === 'lydian') {
    progression = [0, 1, 4, 0];
  } else if (modeLower === 'mixolydian') {
    progression = [0, 3, 4, 0];
  } else if (modeLower === 'dorian') {
    progression = [0, 3, 4, 0];
  } else if (modeLower === 'phrygian') {
    progression = [0, 3, 4, 0];
  } else if (modeLower === 'blues' || modeLower === 'pentatonic') {
    progression = [0, 3, 4, 0];
  } else if (modeLower.includes('minor') || modeLower === 'aeolian') {
    progression = [0, 3, 4, 0];
  } else {
    progression = [0, 3, 4, 0];
  }

  // Парсим целевой аккорд
  let targetRoot = '';
  let targetQuality = 'maj';
  if (targetChord) {
    const parsed = parseChord(targetChord);
    targetRoot = parsed.root;
    targetQuality = parsed.quality;
  }

  for (let i = 0; i < bars; i++) {
    let degree = progression[i % progression.length];
    let rootNoteIdx: number;
    let quality: string;
    let rootNoteStr: string;
    
    if (targetRoot && (forceAllChords || i === 0)) {
      const targetIdx = ALL_NOTES.indexOf(normalizeRoot(targetRoot));
      if (targetIdx !== -1) {
        rootNoteIdx = targetIdx;
        rootNoteStr = ALL_NOTES[rootNoteIdx];
        quality = targetQuality;
      } else {
        rootNoteIdx = keyIdx;
        rootNoteStr = ALL_NOTES[rootNoteIdx];
        quality = getChordQuality(mode, degree);
      }
    } else {
      rootNoteIdx = (keyIdx + degree) % 12;
      rootNoteStr = ALL_NOTES[rootNoteIdx];
      quality = getChordQuality(mode, degree);
    }
    
    const intervals = getChordIntervals(quality);
    
    const thirdNoteIdx = (rootNoteIdx + intervals.third) % 12;
    const thirdNoteStr = ALL_NOTES[thirdNoteIdx];
    const fifthNoteIdx = (rootNoteIdx + intervals.fifth) % 12;
    const fifthNoteStr = ALL_NOTES[fifthNoteIdx];

    const rootOctave = (rootNoteIdx >= 7) ? 2 : 3;
    const thirdOctave = thirdNoteIdx < rootNoteIdx ? rootOctave + 1 : rootOctave;
    const fifthOctave = fifthNoteIdx < rootNoteIdx ? rootOctave + 1 : rootOctave;

    let chordName = rootNoteStr;
    if (quality === 'm') chordName += 'm';
    else if (quality === 'dim') chordName += 'dim';
    else if (quality === 'aug') chordName += 'aug';

    chords.push({
      name: chordName,
      beatStart: i * beatsPerBar,
      durationBeats: beatsPerBar,
      notes: [
        `${rootNoteStr}${rootOctave}`, 
        `${thirdNoteStr}${thirdOctave}`, 
        `${fifthNoteStr}${fifthOctave}`
      ]
    });
  }

  // Генерация нот соло с использованием улучшенного генератора
  const notes = [];
  const lickMode = isMinor ? 'minor' : 'major';
  
  for (let bar = 0; bar < bars; bar++) {
      const lick = generateSmartLick(
        scaleNotes, 
        keyNote || scaleNotes[0] || 'C', 
        lickMode, 
        120, 
        timeSignature, 
        bar,
        chordNotes
      );
      let currentBeat = bar * beatsPerBar;
      
      for (const note of lick.notes) {
          const durBeats = DURATION_TO_BEATS[note.duration] || 0.5;
          notes.push({
              ...note,
              beatStart: currentBeat,
              beatDuration: durBeats
          });
          currentBeat += durBeats;
      }
  }

  return {
    bars,
    totalBeats,
    chords,
    notes,
    tips: []
  };
};